#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-22

# Orchestrator for the gh-rate-limit-tracker live CC-session integration test.
#
# Spawns `claude -p` with a fake `gh` on PATH and captures the JSONL stream for
# later assertion. Real API calls cost tokens — run manually or via
# workflow_dispatch, not on every CI push.
#
# Usage:
#   ./test-session.sh --positive    # primary rate-limit fake (should fire hook)
#   ./test-session.sh --negative    # plain 403 fake (should NOT fire hook)
set -euo pipefail

DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
FAKES_DIR="${DIR}/fakes"
OUT_DIR="${DIR}/out"

MODE=""
if [[ $# -lt 1 ]]; then
  echo "usage: $0 --positive|--negative" >&2
  exit 2
fi
case "$1" in
  --positive) MODE="positive" ;;
  --negative) MODE="negative" ;;
  *)
    echo "unknown flag: $1 (expected --positive or --negative)" >&2
    exit 2
    ;;
esac

if [[ -z "${ANTHROPIC_API_KEY:-}" ]]; then
  echo "error: ANTHROPIC_API_KEY is not set — this harness spawns a real claude session" >&2
  exit 2
fi

if ! command -v claude >/dev/null 2>&1; then
  echo "error: 'claude' CLI not found on PATH" >&2
  exit 2
fi

mkdir -p "${OUT_DIR}"

# Choose the fake to install at fakes/gh. We copy (not symlink) so the harness
# stays self-contained and PATH lookup gets a regular executable.
case "${MODE}" in
  positive)
    SOURCE_FAKE="${FAKES_DIR}/gh"
    # The positive fake IS fakes/gh — already in place.
    ;;
  negative)
    SOURCE_FAKE="${FAKES_DIR}/gh-permission-denied"
    cp "${SOURCE_FAKE}" "${FAKES_DIR}/gh"
    chmod +x "${FAKES_DIR}/gh"
    ;;
esac

# Sanity check: the fake must be executable. `command -v` would find the real
# gh first if PATH is wrong — verify by direct invocation.
if [[ ! -x "${FAKES_DIR}/gh" ]]; then
  echo "error: ${FAKES_DIR}/gh is not executable" >&2
  exit 1
fi

export PATH="${FAKES_DIR}:${PATH}"

# Quote everything. Do NOT echo ANTHROPIC_API_KEY.
echo "[test-session] mode=${MODE} fake=$(readlink -f "${FAKES_DIR}/gh" 2>/dev/null || echo "${FAKES_DIR}/gh")"

set +e
claude -p "Run: gh pr view 1434 --json title" \
  --output-format stream-json \
  --allowedTools Bash \
  --max-turns 3 \
  >"${OUT_DIR}/session.jsonl" \
  2>"${OUT_DIR}/session.err"
CLI_EXIT=$?
set -e

echo "[test-session] claude exit=${CLI_EXIT} stdout=${OUT_DIR}/session.jsonl stderr=${OUT_DIR}/session.err"

# Success = the CLI ran and produced output. Behavioral assertions happen in
# assertions/*.sh. A non-zero claude exit may still be fine (e.g., the model
# stopped early after the rate-limit context was injected).
if [[ ! -s "${OUT_DIR}/session.jsonl" ]]; then
  echo "error: session.jsonl is empty — claude did not produce any output" >&2
  exit 1
fi

exit 0
